            if y - i >= 0:
                ground[y - i][x] = 1
            if y + i < N:
                ground[y + i][x] = 1
            if x - i >= 0:
                ground[y][x - i] = 1
            if x + i < N:
                ground[y][x + i] = 1

    answer = 0
    for i in range(N):
        for j in range(N):
            if ground[i][j] == 1:
                answer += 1
    return answer

